import{_ as e,o as a,c as i,a2 as s}from"./chunks/framework.ByXR59UU.js";const g=JSON.parse('{"title":"OpenShield-XDP","description":"","frontmatter":{},"headers":[],"relativePath":"openshield-xdp/index.md","filePath":"openshield-xdp/index.md","lastUpdated":1782412920000}'),n={name:"openshield-xdp/index.md"};function r(o,t,d,l,p,h){return a(),i("div",null,[...t[0]||(t[0]=[s(`<h1 id="openshield-xdp" tabindex="-1">OpenShield-XDP <a class="header-anchor" href="#openshield-xdp" aria-label="Permalink to &quot;OpenShield-XDP&quot;">​</a></h1><p>XDP-native DDoS mitigation at line rate.</p><p>Inspects and drops attack traffic inside the NIC driver — before the kernel allocates an skb, before iptables runs, before your application sees anything.</p><p>A single attached core handles <strong>10M+ packets per second</strong>. Suspicion scoring, SYN cookies, L7 pattern matching, UDP amplification detection, entropy-based spoofing, and autonomous subnet escalation all run without a context switch.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/AnAverageBeing/OpenShield-XDP.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> OpenShield-XDP</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./install.sh</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openshield</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> load</span></span></code></pre></div><h2 id="detection-surface" tabindex="-1">Detection Surface <a class="header-anchor" href="#detection-surface" aria-label="Permalink to &quot;Detection Surface&quot;">​</a></h2><p>OpenShield classifies <strong>42 attack vectors</strong> across 7 layers.</p><table tabindex="0"><thead><tr><th>Layer</th><th>Vectors</th></tr></thead><tbody><tr><td>L2 — Ethernet / MAC</td><td>Blacklist, whitelist, 802.1Q / 802.1ad / QinQ</td></tr><tr><td>L3 — IP validation</td><td>IPv4 private/bogon (7 ranges), IPv6 private/bogon (6 ranges), malformed headers</td></tr><tr><td>L4 — TCP/UDP flags</td><td>Bogus flags (5 combos), L4 header bounds, TCP doff validation</td></tr><tr><td>Rate-based per IP</td><td>PPS, BPS, TCP, UDP, ICMP, SYN — 6 metrics with additive scoring</td></tr><tr><td>Connection tracking</td><td>Blind SYN-ACK, blind RST, per-IP SYN timestamp</td></tr><tr><td>Amplification &amp; L7</td><td>DNS, generic UDP (8 ports), L7 signature matching (16 rules)</td></tr><tr><td>Statistical anomaly</td><td>SYN/FIN ratio, entropy spoofing, TTL anomaly, packet size anomaly, connection rate</td></tr></tbody></table><h2 id="mitigation" tabindex="-1">Mitigation <a class="header-anchor" href="#mitigation" aria-label="Permalink to &quot;Mitigation&quot;">​</a></h2><ul><li><strong>Ban system</strong> — single IP, LPM subnet, auto /24 escalation, 6-level star system</li><li><strong>Rate limiting</strong> — threshold scoring or token bucket</li><li><strong>Whitelist</strong> — per-IP flags (full bypass, skip ban, skip rate, skip validation)</li><li><strong>SYNPROXY</strong> — cookie-based SYN flood mitigation at XDP line rate</li><li><strong>Panic circuit breaker</strong> — per-CPU probabilistic bulk drop</li></ul><h2 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Stage</th><th>Latency</th></tr></thead><tbody><tr><td>Normal path (all passes)</td><td>~300–500 ns</td></tr><tr><td>Attack path (all modules active)</td><td>~1–2 μs</td></tr><tr><td>At 10M PPS</td><td>~50–70% single-core utilization</td></tr></tbody></table><p><a href="https://github.com/AnAverageBeing/OpenShield-XDP" target="_blank" rel="noreferrer">Repository</a> · <a href="https://discord.gg/qgBMREWWgp" target="_blank" rel="noreferrer">Discord</a></p>`,13)])])}const k=e(n,[["render",r]]);export{g as __pageData,k as default};
